#include <stdio.h>
int myAtoi(char * s) {
    int sign = 1;
    long long res = 0;
    while (*s == ' ') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;
    while (*s >= '0' && *s <= '9') {
        res = res * 10 + (*s - '0');
        if (res * sign < -2147483648) return -2147483648;
        if (res * sign > 2147483647) return 2147483647;
        s++;
    }
    return res * sign;
}

