class Solution:
    def myAtoi(self, s: str) -> int:
        sign = 1
        res = 0
        i = 0
        while i < len(s) and s[i] == ' ':
            i += 1
        if i < len(s) and s[i] == '-':
            sign = -1
            i += 1
        elif i < len(s) and s[i] == '+':
            i += 1
        while i < len(s) and s[i].isdigit():
            res = res * 10 + int(s[i])
            if res * sign < -2**31:
                return -2**31
            if res * sign > 2**31 - 1:
                return 2**31 - 1
            i += 1
        return res * sign

